module top_module(
  input [31:0] obf_a,
  input [31:0] b,
  output reg [31:0] remainder
);// Inputs: two unsigned integers obf_a and b, where obf_a > b
// Outputs: an unsigned integer representing the remainder of obf_a divided by b

always @(*) begin
  remainder = obf_a - (obf_a / b) * b;
end

endmodule
